import { AppBar, Avatar, Badge, Divider, Drawer, Hidden, IconButton, List, ListItem, ListItemIcon, ListItemText, makeStyles, Toolbar, Typography, useTheme } from '@material-ui/core'
import { AddCircle, Dashboard, ExpandMore, PlaylistAddCheck, Menu, ChevronLeft, ChevronRight, Settings } from '@material-ui/icons';
import phil from '../images/phil.png'
import React from 'react';
import clsx from 'clsx';
import { withStyles } from '@material-ui/styles';

const StyledBadge = withStyles((theme) => ({
  badge: {
    backgroundColor: '#44b700',
    color: '#44b700',
    boxShadow: `0 0 0 2px ${theme.palette.background.paper}`
  }
}))(Badge);

const drawerWidth = 240;

const useStyle = makeStyles(theme => {
  return {
    root: {
      display: 'flex',
      '& .MuiToolbar-root': {
        boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;'
      },
      '& .MuiCard-root': {
        boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;',

        '&:hover': {
          transform: 'rotateZ(-1.5deg) scale(1.1)',
          boxShadow: '3px 5px 7px rgba(0, 0, 0, 0.2)',
          transition: 'all ease-out 0.2s'
        }
      },
      justifyContent: 'center'
    },
    page: {
      background: '#f9fbfd',
      width: '100%',
      padding: theme.spacing(1)
    },


    appBar: {
      transition: theme.transitions.create(['margin', 'width'], {
        easing: theme.transitions.easing.sharp,
        duration: theme.transitions.duration.leavingScreen,
      }),
    },
    appBarShift: {
      width: `calc(100% - ${drawerWidth}px)`,
      marginLeft: drawerWidth,
      transition: theme.transitions.create(['margin', 'width'], {
        easing: theme.transitions.easing.easeOut,
        duration: theme.transitions.duration.enteringScreen,
      }),
    },
    menuButton: {
      marginRight: theme.spacing(2),
    },
    hide: {
      display: 'none',
    },


    drawer: {
      width: drawerWidth,
      flexShrink: 0
    },
    drawerPaper: {
      width: drawerWidth,
      background: '#162276',
      color: 'white'
    },
    drawerHeader: {
      display: 'flex',
      alignItems: 'center',
      padding: theme.spacing(0, 1),
      // necessary for content to be below app bar
      ...theme.mixins.toolbar,
      justifyContent: 'space-between',
    },
    content: {
      flexGrow: 1,
      padding: theme.spacing(3),
      transition: theme.transitions.create('margin', {
        easing: theme.transitions.easing.sharp,
        duration: theme.transitions.duration.leavingScreen,
      }),
      marginLeft: -drawerWidth,
    },
    contentShift: {
      transition: theme.transitions.create('margin', {
        easing: theme.transitions.easing.easeOut,
        duration: theme.transitions.duration.enteringScreen,
      }),
      marginLeft: 0,
    },


    toolbar: theme.mixins.toolbar,
    title: {
      flexGrow: '1'
    },
    sidebar: {
      width: drawerWidth
    },
    logoContainer: {
      maxWidth: '40px',
      margin: '2px auto'
    },
    logo: {
      width: '100%',
      paddingTop: '10%'
    },
    lists: {
      marginTop: '10px'
    },
    fullList: {
      width: 'auto',
    },
  }
});


export default function Layout({ children }) {
  const classes = useStyle()
  const theme = useTheme();
  const [open, setOpen] = React.useState(false);
  const handleDrawerOpen = () => {
    setOpen(true);
  };

  const handleDrawerClose = () => {
    setOpen(false);
  };

  const studentSideLinks = [
    {
      text: 'Dashboard',
      icon: <Dashboard color='error' />,
      path: '/studentDashboard',
      id: 1
    },
    {
      text: 'Subjects',
      icon: <PlaylistAddCheck color='error' />,
      path: '/studentDashboard',
      id: 2
    },
    {
      text: 'Join a Class',
      icon: <AddCircle color='error' />,
      path: '/studentDashboard',
      id: 3
    },
  ]

  return (
    <div className={classes.root}>
      {/* // appbar */}

      <AppBar className={clsx(classes.appBar, { [classes.appBarShift]: open, })} color='inherit' elevation={0}>
        <Toolbar>
          <IconButton
            color="inherit"
            aria-label="open drawer"
            onClick={handleDrawerOpen}
            edge="start"
            className={clsx(classes.menuButton, open && classes.hide)}
          >
            <Menu />
          </IconButton>
          
          <div className={classes.title}>
            <h1 style={{color: '#162276'}} >URSAC Online</h1>
          </div>

          <Hidden mdDown>
          <IconButton>
            <StyledBadge
              overlap="circular"
              anchorOrigin={{
                vertical: 'bottom',
                horizontal: 'right',
              }}
              variant="dot"
            >
              <Avatar src={phil} />
            </StyledBadge>
          </IconButton>
          <Typography variant='caption'>
            Cris Philip V. Cajurao
            <IconButton>
              <ExpandMore />
            </IconButton>
          </Typography>
          </Hidden>
        </Toolbar>
      </AppBar>

      {/* // sidebar */}
      <Drawer
        className={classes.drawer}
        variant="persistent"
        anchor="left"
        open={open}
        classes={{
          paper: classes.drawerPaper,
        }}
      >
        <div className={classes.drawerHeader}>
          <Typography variant='h5' >
            Student
          </Typography>
          <IconButton onClick={handleDrawerClose}>
            {theme.direction === 'ltr' ? <ChevronLeft color='error' /> : <ChevronRight />}
          </IconButton>
        </div>
        <Divider />
        <List>
          {studentSideLinks.map((links) => (
            <ListItem button key={links.id}>
              <ListItemIcon>{links.icon}</ListItemIcon>
              <ListItemText primary={links.text} />
            </ListItem>
          ))}
        </List>
        <Divider color='error' />
        <List>
          <ListItem button>
            <ListItemIcon><Settings color='error' /></ListItemIcon>
            <ListItemText primary='Settings' />
          </ListItem>
        </List>
      </Drawer>

      <div
        className={clsx(classes.content, {
          [classes.contentShift]: open,
        })}
      >
        <div className={classes.drawerHeader} />
        <div className={classes.page}>
          <div className={classes.toolbar} elevation={0}></div>
          {children}
        </div>
      </div>
    </div>
  )
}
